import { DreamEntry } from '../types';
import { LOCAL_STORAGE_KEY } from '../constants';

/**
 * Loads dream entries from local storage.
 * @returns An array of DreamEntry objects, or an empty array if none are found.
 */
export const loadDreamEntries = (): DreamEntry[] => {
  try {
    const serializedEntries = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (serializedEntries === null) {
      return [];
    }
    return JSON.parse(serializedEntries);
  } catch (error) {
    console.error("Error loading dream entries from local storage:", error);
    return [];
  }
};

/**
 * Saves dream entries to local storage.
 * @param entries The array of DreamEntry objects to save.
 */
export const saveDreamEntries = (entries: DreamEntry[]): void => {
  try {
    const serializedEntries = JSON.stringify(entries);
    localStorage.setItem(LOCAL_STORAGE_KEY, serializedEntries);
  } catch (error) {
    console.error("Error saving dream entries to local storage:", error);
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  children: React.ReactNode;
}

const Button: React.FC<ButtonProps> = ({
  variant = 'primary',
  size = 'md',
  children,
  className = '',
  disabled,
  ...props
}) => {
  const baseStyles = 'font-medium rounded-full transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2';
  let variantStyles = '';
  let sizeStyles = '';

  switch (variant) {
    case 'primary':
      variantStyles = 'bg-gradient-to-r from-purple-500 to-indigo-600 hover:from-purple-600 hover:to-indigo-700 text-white shadow-lg';
      break;
    case 'secondary':
      variantStyles = 'bg-gray-700 hover:bg-gray-600 text-white shadow-md';
      break;
    case 'outline':
      variantStyles = 'border border-indigo-400 text-indigo-300 hover:bg-indigo-900 hover:text-white';
      break;
    case 'ghost':
      variantStyles = 'text-indigo-300 hover:bg-indigo-900';
      break;
  }

  switch (size) {
    case 'sm':
      sizeStyles = 'px-3 py-1 text-sm';
      break;
    case 'md':
      sizeStyles = 'px-5 py-2 text-base';
      break;
    case 'lg':
      sizeStyles = 'px-6 py-3 text-lg';
      break;
  }

  return (
    <button
      className={`${baseStyles} ${variantStyles} ${sizeStyles} ${disabled ? 'opacity-50 cursor-not-allowed' : ''} ${className}`}
      disabled={disabled}
      {...props}
    >
      {children}
    </button>
  );
};

export default Button;

