import React, { useState, useEffect, useCallback } from 'react';
import { DreamEntry, AppMode, Prompt, ToolType, ApiResponse } from './types';
import { loadDreamEntries, saveDreamEntries } from './services/localStorageService';
import {
  PREDEFINED_PROMPTS,
  APP_NAME,
} from './constants';
import DreamscapeBackground from './components/DreamscapeBackground';
import Button from './components/Button';
import EntryCard from './components/EntryCard';
import CreateEntryForm from './components/CreateEntryForm';
import EntryDetail from './components/EntryDetail';
import Modal from './components/Modal';
import LoadingSpinner from './components/LoadingSpinner';
import ApiKeyPrompt from './components/ApiKeyPrompt';
import { interpretDream, generateStorySpark, generateImageVisualizer, handleApiKeySelection, checkApiKeyStatus } from './services/geminiService';

const App: React.FC = () => {
  const [entries, setEntries] = useState<DreamEntry[]>([]);
  const [currentMode, setCurrentMode] = useState<AppMode>('list');
  const [selectedEntry, setSelectedEntry] = useState<DreamEntry | null>(null);
  const [currentPrompt, setCurrentPrompt] = useState<Prompt | null>(null);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // AI Modal State
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiResult, setAiResult] = useState<string>('');
  const [aiImageResult, setAiImageResult] = useState<string | null>(null);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiError, setAiError] = useState<string | null>(null);
  const [aiToolTitle, setAiToolTitle] = useState<string>('');

  // API Key state for image generation (which explicitly requires user selection)
  const [apiKeyRequiredMessage, setApiKeyRequiredMessage] = useState<string | null>(null);

  // Load entries on initial mount
  useEffect(() => {
    setEntries(loadDreamEntries());

    const handleOnlineStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleOnlineStatus);
    window.addEventListener('offline', handleOnlineStatus);

    return () => {
      window.removeEventListener('online', handleOnlineStatus);
      window.removeEventListener('offline', handleOnlineStatus);
    };
  }, []);

  // Save entries whenever the 'entries' state changes
  useEffect(() => {
    saveDreamEntries(entries);
  }, [entries]);

  const addOrUpdateEntry = useCallback((entry: DreamEntry) => {
    setEntries((prevEntries) => {
      const existingIndex = prevEntries.findIndex((e) => e.id === entry.id);
      if (existingIndex > -1) {
        const updatedEntries = [...prevEntries];
        updatedEntries[existingIndex] = entry;
        return updatedEntries;
      }
      return [entry, ...prevEntries];
    });
    setCurrentMode('list');
    setSelectedEntry(null);
  }, [setEntries]);

  const deleteEntry = useCallback((id: string) => {
    setEntries((prevEntries) => prevEntries.filter((entry) => entry.id !== id));
    setCurrentMode('list');
    setSelectedEntry(null);
  }, [setEntries]);

  const openEntryDetail = useCallback((id: string) => {
    const entry = entries.find((e) => e.id === id);
    if (entry) {
      setSelectedEntry(entry);
      setCurrentMode('detail');
    }
  }, [entries]);

  const generateRandomPrompt = useCallback(() => {
    const randomIndex = Math.floor(Math.random() * PREDEFINED_PROMPTS.length);
    setCurrentPrompt(PREDEFINED_PROMPTS[randomIndex]);
  }, []);

  // Handle AI Tool triggering
  const triggerAITool = useCallback(async (entry: DreamEntry, toolType: ToolType) => {
    setAiLoading(true);
    setAiResult('');
    setAiImageResult(null);
    setAiError(null);
    setIsAiModalOpen(true);
    setApiKeyRequiredMessage(null);

    let result: ApiResponse;

    const checkKeyResponse = await checkApiKeyStatus(toolType);
    if (!checkKeyResponse.success) {
      setApiKeyRequiredMessage(checkKeyResponse.message);
      setAiLoading(false);
      return;
    }

    try {
      if (toolType === 'dreamInterpreter') {
        setAiToolTitle('AI Dream Interpretation');
        result = await interpretDream(entry.content, entry.imageUrl);
      } else if (toolType === 'storySpark') {
        setAiToolTitle('AI Story Spark');
        result = await generateStorySpark(entry.content);
      } else if (toolType === 'aiVisualizer') {
        setAiToolTitle('AI Visualizer');
        const keywords = entry.tags.length > 0 ? entry.tags.join(', ') : entry.title;
        result = await generateImageVisualizer(keywords);
        if (result.success && result.data) {
          setAiImageResult(result.data);
          setAiResult("Image generated successfully!");
        }
      } else {
        result = { success: false, message: 'Unknown AI tool selected.' };
      }

      if (result.success) {
        setAiResult(result.data);
      } else {
        setAiError(result.message);
        if (result.message.includes("API key error")) {
          setApiKeyRequiredMessage(result.message);
        }
      }
    } catch (error: any) {
      console.error("Error during AI tool call:", error);
      setAiError(`An unexpected error occurred: ${error.message}`);
    } finally {
      setAiLoading(false);
    }
  }, []); // eslint-disable-next-line react-hooks/exhaustive-deps

  const handleApiKeyPromptSelect = useCallback(async () => {
    setApiKeyRequiredMessage(null); // Clear previous message
    const result = await handleApiKeySelection();
    if (!result.success) {
      setAiError(result.message);
    } else {
      // Assume success and close modal, user will retry AI action
      // Or simply leave the modal open but clear the specific API key prompt,
      // letting the user retry the AI action.
      // For now, let's keep it simple and just clear the message.
      setAiError(null);
    }
  }, []); // eslint-disable-next-line react-hooks/exhaustive-deps

  const renderContent = () => {
    switch (currentMode) {
      case 'create':
        return (
          <CreateEntryForm
            initialEntry={selectedEntry || undefined}
            onSave={addOrUpdateEntry}
            onCancel={() => {
              setCurrentMode('list');
              setSelectedEntry(null);
            }}
            onDelete={deleteEntry}
          />
        );
      case 'detail':
        return selectedEntry ? (
          <EntryDetail
            entry={selectedEntry}
            onBack={() => {
              setCurrentMode('list');
              setSelectedEntry(null);
            }}
            onEdit={(entryToEdit) => {
              setSelectedEntry(entryToEdit);
              setCurrentMode('create');
            }}
            onTriggerAITool={triggerAITool}
            isOnline={isOnline}
          />
        ) : (
          <div className="text-center text-white text-xl mt-16">Entry not found.</div>
        );
      case 'list':
      default:
        return (
          <>
            {currentPrompt && (
              <div className="bg-gradient-to-r from-indigo-800 to-purple-800 p-6 rounded-xl shadow-xl text-white text-center mb-8 mx-auto max-w-xl border border-purple-700">
                <h3 className="text-xl font-semibold mb-2">Prompt for Inspiration:</h3>
                {currentPrompt.type === 'text' ? (
                  <p className="text-lg italic text-indigo-100 mb-4">{currentPrompt.text}</p>
                ) : (
                  <>
                    <p className="text-lg italic text-indigo-100 mb-4">{currentPrompt.text}</p>
                    <img src={`https://picsum.photos/400/200?random=${currentPrompt.id}`} alt="Visual Prompt" className="w-full h-auto rounded-lg mt-4 object-cover" />
                  </>
                )}

                <Button variant="outline" size="sm" onClick={generateRandomPrompt}>
                  Next Prompt
                </Button>
              </div>
            )}

            {entries.length === 0 ? (
              <div className="text-center text-indigo-200 text-xl mt-16 p-6 bg-indigo-900 bg-opacity-30 rounded-xl max-w-md mx-auto">
                <p className="mb-4">You haven't woven any dreams yet!</p>
                <p>Click "New Entry" to start your journey.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-4 md:p-8 max-w-6xl mx-auto pb-32">
                {entries.map((entry) => (
                  <EntryCard key={entry.id} entry={entry} onClick={openEntryDetail} />
                ))}
              </div>
            )}
          </>
        );
    }
  };

  return (
    <div className="relative min-h-screen font-sans text-white">
      <DreamscapeBackground />

      <div className="relative z-10 p-4 pb-20"> {/* pb-20 for fixed footer */}
        <header className="flex flex-col sm:flex-row justify-between items-center text-center sm:text-left mb-8 py-4 bg-gradient-to-r from-indigo-900/50 to-purple-900/50 backdrop-blur-sm rounded-xl px-6 shadow-lg border border-indigo-700">
          <h1 className="text-5xl font-extrabold text-white tracking-tight mb-4 sm:mb-0">
            {APP_NAME}
          </h1>
          <div className="flex flex-wrap justify-center gap-4">
            <Button
              onClick={() => {
                setCurrentMode('create');
                setSelectedEntry(null);
              }}
              variant="primary"
            >
              + New Entry
            </Button>
            <Button onClick={generateRandomPrompt} variant="outline">
              Inspire Me!
            </Button>
          </div>
        </header>

        <main className="min-h-[calc(100vh-180px)]"> {/* Adjust height for header/footer */}
          {renderContent()}
        </main>
      </div>

      {/* AI Result Modal */}
      <Modal isOpen={isAiModalOpen} onClose={() => setIsAiModalOpen(false)} title={aiToolTitle}>
        {aiLoading && <LoadingSpinner />}
        {aiError && <p className="text-red-300 mb-4 text-center">{aiError}</p>}
        {apiKeyRequiredMessage && (
          <ApiKeyPrompt onSelectKey={handleApiKeyPromptSelect} message={apiKeyRequiredMessage} />
        )}
        {!aiLoading && !aiError && aiResult && !apiKeyRequiredMessage && (
          <>
            {aiImageResult ? (
              <div className="flex flex-col items-center">
                <img src={aiImageResult} alt="AI Generated Visual" className="max-w-full h-auto rounded-lg shadow-lg mb-4" />
                <p className="text-indigo-100 text-lg text-center">{aiResult}</p>
              </div>
            ) : (
              <p className="whitespace-pre-wrap text-indigo-100 text-lg">{aiResult}</p>
            )}
          </>
        )}
        {!aiLoading && !aiError && !aiResult && !apiKeyRequiredMessage && <p className="text-indigo-300 text-center">No result yet.</p>}
      </Modal>

      {/* Sticky Footer for Mobile-First Approach */}
      <footer className="fixed bottom-0 left-0 right-0 z-20 bg-gradient-to-r from-indigo-900 to-purple-900 p-4 shadow-top border-t border-indigo-700 flex justify-around items-center md:hidden">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => {
            setCurrentMode('list');
            setSelectedEntry(null);
          }}
          className="flex flex-col items-center text-sm"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" />
          </svg>
          List
        </Button>
        <Button
          variant="primary"
          size="sm"
          onClick={() => {
            setCurrentMode('create');
            setSelectedEntry(null);
          }}
          className="flex flex-col items-center text-sm"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
          </svg>
          New
        </Button>
        <Button variant="outline" size="sm" onClick={generateRandomPrompt} className="flex flex-col items-center text-sm">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
          </svg>
          Inspire
        </Button>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse, Part } from '@google/genai';
// Add GEMINI_MODEL_TEXT_COMPLEX to the import list
import { GEMINI_MODEL_TEXT, GEMINI_MODEL_IMAGE, GEMINI_MODEL_TEXT_COMPLEX, INITIAL_SYSTEM_INSTRUCTION_DREAM_INTERPRETER, INITIAL_SYSTEM_INSTRUCTION_STORY_SPARK, INITIAL_SYSTEM_INSTRUCTION_AI_VISUALIZER } from '../constants';
import { ApiResponse, ToolType } from '../types';

// Helper function to initialize GoogleGenAI client (called just before making an API request)
const getGeminiClient = () => {
  const apiKey = process.env.API_KEY; // Assumed to be injected
  if (!apiKey) {
    throw new Error('Google Gemini API key is not set. Please select an API key.');
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert data URL to Parts for Gemini Vision models
const dataURLToImagePart = (dataUrl: string, mimeType: string): Part => {
  const base64Data = dataUrl.split(',')[1];
  return {
    inlineData: {
      mimeType: mimeType,
      data: base64Data,
    },
  };
};

// Generic API caller for text generation
const callGeminiTextModel = async (
  prompt: string,
  systemInstruction: string = INITIAL_SYSTEM_INSTRUCTION_DREAM_INTERPRETER,
  modelName: string = GEMINI_MODEL_TEXT
): Promise<ApiResponse> => {
  try {
    const ai = getGeminiClient();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.9,
        topP: 0.95,
        topK: 64,
        maxOutputTokens: 1024,
      },
    });
    const text = response.text;
    if (!text) {
      throw new Error('No text content received from Gemini API.');
    }
    return { success: true, message: 'Interpretation successful', data: text };
  } catch (error: any) {
    console.error(`Error calling Gemini text model (${modelName}):`, error);
    // Specific error handling for API key not found
    if (error.message.includes("API key not found") || error.message.includes("Unauthorized") || error.message.includes("Requested entity was not found.")) {
      return { success: false, message: "API key error: Please ensure you have a valid, paid API key selected for this feature." };
    }
    return { success: false, message: `Failed to get interpretation: ${error.message}` };
  }
};

// Dream Interpreter
export const interpretDream = async (
  dreamText: string,
  dreamImage?: string // Base64 image data url
): Promise<ApiResponse> => {
  if (!dreamText && !dreamImage) {
    return { success: false, message: "Please provide either text or an image for dream interpretation." };
  }

  const parts: Part[] = [];
  if (dreamImage) {
    // Try to infer mime type, default to jpeg if unknown
    const mimeMatch = dreamImage.match(/^data:(image\/(png|jpeg|webp));base64,/);
    const mimeType = mimeMatch ? mimeMatch[1] : 'image/jpeg';
    parts.push(dataURLToImagePart(dreamImage, mimeType));
  }
  if (dreamText) {
    parts.push({ text: `Analyze this dream:\n${dreamText}` });
  }

  try {
    const ai = getGeminiClient();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: GEMINI_MODEL_IMAGE, // Use image model if image is provided, or for a richer response
      contents: { parts: parts },
      config: {
        systemInstruction: INITIAL_SYSTEM_INSTRUCTION_DREAM_INTERPRETER,
        temperature: 0.9,
        topP: 0.95,
        topK: 64,
        maxOutputTokens: 1024,
      },
    });
    const text = response.text;
    if (!text) {
      throw new Error('No text content received from Gemini API.');
    }
    return { success: true, message: 'Interpretation successful', data: text };
  } catch (error: any) {
    console.error("Error interpreting dream:", error);
    if (error.message.includes("Requested entity was not found.") || error.message.includes("403 Forbidden")) {
        return { success: false, message: "API key error: This feature requires a paid API key. Please select one through the 'Select API Key' option." };
    }
    return { success: false, message: `Failed to interpret dream: ${error.message}` };
  }
};


// Story Spark
export const generateStorySpark = async (
  entryContent: string
): Promise<ApiResponse> => {
  const prompt = `Given the following entry, provide 3 creative suggestions for continuing the story or adding a new twist:\n\n"${entryContent}"`;
  return callGeminiTextModel(prompt, INITIAL_SYSTEM_INSTRUCTION_STORY_SPARK, GEMINI_MODEL_TEXT_COMPLEX);
};

// AI Visualizer
export const generateImageVisualizer = async (
  keywords: string
): Promise<ApiResponse> => {
  const prompt = `Generate a unique, abstract, and aesthetically pleasing image based on these descriptive keywords: "${keywords}". Focus on vivid colors, ethereal textures, and a dreamlike quality.`;

  try {
    // Check if the API key is selected (required for image models)
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        return { success: false, message: "Please select an API key for image generation via the 'Select API Key' button." };
      }
    } else {
        // Fallback for environments without window.aistudio, assuming API_KEY is set.
        // This is a less robust check, as window.aistudio is the official way for this context.
        if (!process.env.API_KEY) {
            return { success: false, message: "API key not found. Ensure API_KEY is set or select one." };
        }
    }

    const ai = getGeminiClient();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: GEMINI_MODEL_IMAGE,
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1", // Default to 1:1 for artistic vision
          imageSize: "1K" // Default to 1K resolution
        },
        systemInstruction: INITIAL_SYSTEM_INSTRUCTION_AI_VISUALIZER
      },
    });

    for (const candidate of response.candidates || []) {
      for (const part of candidate.content?.parts || []) {
        if (part.inlineData) {
          const base64EncodeString: string = part.inlineData.data;
          const imageUrl = `data:${part.inlineData.mimeType};base64,${base64EncodeString}`;
          return { success: true, message: 'Image generated successfully', data: imageUrl };
        }
      }
    }
    throw new Error('No image data received from Gemini API.');
  } catch (error: any) {
    console.error("Error generating image visualizer:", error);
    if (error.message.includes("Requested entity was not found.") || error.message.includes("403 Forbidden") || error.message.includes("API key error: This feature requires a paid API key.")) {
        return { success: false, message: "API key error: This feature requires a paid API key. Please select one through the 'Select API Key' option." };
    }
    return { success: false, message: `Failed to generate image: ${error.message}` };
  }
};

// Function to handle API key selection
export const handleApiKeySelection = async (): Promise<ApiResponse> => {
  if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
    try {
      await window.aistudio.openSelectKey();
      // Assume success for race condition
      return { success: true, message: "API key selection initiated. Please verify in the dialog." };
    } catch (error: any) {
      console.error("Error opening API key selection dialog:", error);
      return { success: false, message: `Failed to open API key selection: ${error.message}` };
    }
  } else {
    return { success: false, message: "API key selection not available in this environment. Ensure your API_KEY is set." };
  }
};

export const checkApiKeyStatus = async (toolType: ToolType): Promise<ApiResponse> => {
    // Only GEMINI_MODEL_IMAGE requires explicit check via window.aistudio.
    // Other models are assumed to work with process.env.API_KEY if present.
    if (toolType === 'aiVisualizer') {
        if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
            try {
                const hasKey = await window.aistudio.hasSelectedApiKey();
                if (!hasKey) {
                    return { success: false, message: "No API key selected for this feature." };
                }
            } catch (error) {
                console.error("Error checking API key status:", error);
                return { success: false, message: "Could not verify API key status." };
            }
        } else {
            // For environments where window.aistudio is not available, we assume process.env.API_KEY is handled externally.
            if (!process.env.API_KEY) {
                return { success: false, message: "API key not found in environment." };
            }
        }
    }
    // For other tool types, we just check if process.env.API_KEY is available as a basic check.
    // The actual API call will handle more specific errors.
    if (!process.env.API_KEY) {
      return { success: false, message: "API key not found in environment for basic features." };
    }

    return { success: true, message: "API key appears to be available." };
};

import React, { createContext, useState, useEffect, useContext, ReactNode, useCallback } from 'react';

// Define the shape of the locale context
interface LocaleContextType {
  locale: string;
  setLocale: (newLocale: string) => void;
  t: (key: string) => string; // Translation function
}

// Create the context with a default (null) value
const LocaleContext = createContext<LocaleContextType | undefined>(undefined);

// Load translations dynamically
const loadTranslations = async (locale: string) => {
  try {
    const response = await fetch(`/locales/${locale}.json`);
    if (!response.ok) {
      throw new Error(`Failed to load translations for locale: ${locale}`);
    }
    return response.json();
  } catch (error) {
    console.error(`Error loading translations for ${locale}:`, error);
    return {};
  }
};

// Locale Provider component
export const LocaleProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [locale, setLocaleState] = useState<string>(() => {
    // Initialize locale from localStorage or default to 'en'
    return localStorage.getItem('dreamWeaverLocale') || 'en';
  });
  const [translations, setTranslations] = useState<{ [key: string]: string }>({});

  useEffect(() => {
    // Load translations whenever the locale changes
    loadTranslations(locale).then(setTranslations);
    // Save locale preference to localStorage
    localStorage.setItem('dreamWeaverLocale', locale);
  }, [locale]);

  // Translation function
  const t = useCallback((key: string): string => {
    return translations[key] || key; // Return key if translation not found
  }, [translations]);

  // Function to update the locale
  const setLocale = useCallback((newLocale: string) => {
    setLocaleState(newLocale);
  }, []);

  const contextValue = { locale, setLocale, t };

  return (
    <LocaleContext.Provider value={contextValue}>
      {children}
    </LocaleContext.Provider>
  );
};

// Custom hook to use the locale context
export const useLocale = () => {
  const context = useContext(LocaleContext);
  if (context === undefined) {
    throw new Error('useLocale must be used within a LocaleProvider');
  }
  return context;
};

