import { GoogleGenAI, GenerateContentResponse, Part } from '@google/genai';
import { GEMINI_MODEL_TEXT, GEMINI_MODEL_IMAGE, GEMINI_MODEL_TEXT_COMPLEX } from '../constants'; // Only import model names now
