import React, { createContext, useState, useEffect, useContext, ReactNode, useCallback } from 'react';

// Define the shape of the locale context
interface LocaleContextType {
  locale: string;
  setLocale: (newLocale: string) => void;
  t: (key: string) => string; // Translation function
}

// Create the context with a default (null) value
const LocaleContext = createContext<LocaleContextType | undefined>(undefined);

// Load translations dynamically
const loadTranslations = async (locale: string) => {
  try {
    const response = await fetch(`/locales/${locale}.json`);
    if (!response.ok) {
      throw new Error(`Failed to load translations for locale: ${locale}`);
    }
    return response.json();
  } catch (error) {
    console.error(`Error loading translations for ${locale}:`, error);
    return {};
  }
};

// Locale Provider component
export const LocaleProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [locale, setLocaleState] = useState<string>(() => {
    // Initialize locale from localStorage or default to 'en'
    return localStorage.getItem('dreamWeaverLocale') || 'en';
  });
  const [translations, setTranslations] = useState<{ [key: string]: string }>({});

  useEffect(() => {
    // Load translations whenever the locale changes
    loadTranslations(locale).then(setTranslations);
    // REMOVED: localStorage.setItem('dreamWeaverLocale', locale); from here.
    // Saving to localStorage should only happen when the user explicitly selects a language
    // via handleLanguageSelect in App.tsx. This prevents 'en' from being written
    // immediately on first load, allowing the language selector to appear.
  }, [locale]);

  // Translation function
  const t = useCallback((key: string): string => {
    return translations[key] || key; // Return key if translation not found
  }, [translations]);

  // Function to update the locale
  const setLocale = useCallback((newLocale: string) => {
    setLocaleState(newLocale);
    // localStorage.setItem('dreamWeaverLocale', newLocale); // App.tsx's handleLanguageSelect already does this
  }, []);

  const contextValue = { locale, setLocale, t };

  return (
    <LocaleContext.Provider value={contextValue}>
      {children}
    </LocaleContext.Provider>
  );
};

// Custom hook to use the locale context
export const useLocale = () => {
  const context = useContext(LocaleContext);
  if (context === undefined) {
    throw new Error('useLocale must be used within a LocaleProvider');
  }
  return context;
};

// services/geolocationService.ts

export interface UserLocation {
  latitude: number;
  longitude: number;
}

export interface GeolocationResponse {
  success: boolean;
  location?: UserLocation;
  error?: GeolocationPositionError | string;
  message: string; // This will now be a translation key
}

/**
 * Attempts to get the user's current geographical location.
 * Requires 'geolocation' permission.
 * @returns A promise that resolves to a GeolocationResponse indicating success/failure and location data.
 */
export const getUserLocation = (): Promise<GeolocationResponse> => {
  return new Promise((resolve) => {
    if (!navigator.geolocation) {
      resolve({
        success: false,
        message: 'geolocation_unsupportedBrowser', // Translation key
        error: 'UnsupportedBrowser',
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        resolve({
          success: true,
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          message: 'locationFetchedSuccessfully', // Translation key
        });
      },
      (error) => {
        let messageKey: string;
        switch (error.code) {
          case error.PERMISSION_DENIED:
            messageKey = 'geolocation_permissionDenied'; // Translation key
            break;
          case error.POSITION_UNAVAILABLE:
            messageKey = 'geolocation_positionUnavailable'; // Translation key
            break;
          case error.TIMEOUT:
            messageKey = 'geolocation_timeout'; // Translation key
            break;
          default:
            messageKey = 'geolocation_unknownError'; // Translation key
            break;
        }
        resolve({
          success: false,
          message: messageKey,
          error: error,
        });
      },
      {
        enableHighAccuracy: true,
        timeout: 10000, // 10 seconds
        maximumAge: 0, // No cached position
      }
    );
  });
};

import React, { useState, useEffect, useMemo } from 'react';
import Modal from './Modal';
import Input from './Input';
import SimulatedUserCard from './SimulatedUserCard';
import { SimulatedUser } from '../types';
import { SIMULATED_USERS } from '../data/simulatedUsers';
import { useLocale } from '../context/LocaleContext';

interface FindUsersModalProps {
  isOpen: boolean;
  onClose: () => void;
  onViewProfile: (user: SimulatedUser) => void;
  followedUserIds: Set<string>; // New prop
  onToggleFollow: (userId: string) => void; // New prop
  currentUserKeywords: string[]; // New prop for shared interests
}

const FindUsersModal: React.FC<FindUsersModalProps> = ({
  isOpen,
  onClose,
  onViewProfile,
  followedUserIds, // Destructure new prop
  onToggleFollow, // Destructure new prop
  currentUserKeywords // Destructure new prop
}) => {
  const { t } = useLocale();
  const [searchTerm, setSearchTerm] = useState('');
  const [filteredUsers, setFilteredUsers] = useState<SimulatedUser[]>([]);

  useEffect(() => {
    if (isOpen) {
      setSearchTerm(''); // Reset search term when modal opens
      // Initial display: a selection of users, not necessarily "nearby" until location is fetched
      setFilteredUsers(SIMULATED_USERS.slice(0, 5));
    }
  }, [isOpen]);

  // Filter users based on search term
  useEffect(() => {
    if (searchTerm) {
      setFilteredUsers(
        SIMULATED_USERS.filter((user) =>
          user.username.toLowerCase().includes(searchTerm.toLowerCase())
        )
      );
    } else {
      setFilteredUsers(SIMULATED_USERS.slice(0, 5)); // Show featured users if search is empty
    }
  }, [searchTerm]);

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={t('findUsersModalTitle')}>
      <Input
        id="userSearch"
        placeholder={t('searchUsersPlaceholder')}
